import java.util.Arrays;

public int minMoves(int[] seats, int[] students) {
    Arrays.sort(seats);
    Arrays.sort(students);

    int moves = 0;
    for (int i = 0; i < seats.length; i++) {
        moves += Math.abs(seats[i] - students[i]);
    }
    return moves;
}
```

